#include "game/faction/FactionSystem.h"
namespace fw { void FactionSystem::Reset(){ m_reputation.clear(); m_reputation["villagers"]=0; m_reputation["guards"]=0; } void FactionSystem::AddReputation(const std::string& factionId,int delta){ m_reputation[factionId]+=delta; } int FactionSystem::GetReputation(const std::string& factionId) const { auto it=m_reputation.find(factionId); return it==m_reputation.end()?0:it->second; } std::string FactionSystem::DescribeStanding(const std::string& factionId) const { int rep=GetReputation(factionId); if(rep>=20) return "Trusted"; if(rep>=5) return "Friendly"; if(rep<=-20) return "Hostile"; if(rep<=-5) return "Distrusted"; return "Neutral"; } }
